// Practice-question data for AZ-900 (Microsoft Azure Fundamentals).
//
// AZ900_QUESTIONS now contains REAL exam-prep questions extracted directly
// from the user's authoritative German PDF (Pruefungsfragen_AZ-900_De.pdf,
// 564 questions total, one per PDF page in reverse page order — page N =
// Frage (565-N)). Extraction/parsing script + intermediate JSON live in the
// sandbox at /home/claude/az900_extract/ (parse_final.py + fix_combinatorial.py)
// for reference when extracting the next batch.
//
// PROGRESS: ALL 564 questions from the PDF processed. 498 confidently
// verified and included, fully QA-audited (zero duplicate-option/multi-
// colon/leading-artifact issues on the final full-file re-scan). 66
// skipped total across all 6 batches — ambiguous Ja/Nein combinatorial
// answer grids, matching/drag-drop questions whose description text
// wasn't in the text layer, and Q429 (a full-page image-only question
// with no extractable text at all). See git history for the exact
// question-number breakdown per batch. Two questions (Q32, Q163) have a
// real reference screenshot (imageUrl) extracted directly from the PDF;
// 35 questions (in the underlined-text format) have underlinedText set
// and verified against their prompt. Extraction scripts + this process
// are documented in scripts/az900-extraction/ for any future re-run or
// recovery of the skipped questions.
// `real-az900-<n>` id scheme and topicId mapping:
//   "Beschreiben von Cloud-Konzepten"            -> "cloud-konzepte"
//   "Beschreiben Sie die Azure-Architektur..."   -> "azure-architektur"
//   "Beschreiben Sie Azure-Management..."        -> "azure-verwaltung"
// Section sizing (lib/practiceSections.ts) is fully automatic — once all
// 564 are in, it will produce 12 sections of 50 (last one with 14) with no
// further code changes needed.

export type PracticeOptionId = "A" | "B" | "C" | "D" | "E" | "F";

export type SingleChoiceQuestion = {
  type?: "single";
  id: string;
  topicId: string;
  prompt: string;
  /** For "check the underlined text" questions: the exact substring of
   * `prompt` that should be rendered with an underline, so the student
   * knows which part to evaluate/replace. */
  underlinedText?: string;
  /** Path to a reference screenshot the question depends on (e.g. an Azure
   * Portal navigation panel), shown above the answer options. */
  imageUrl?: string;
  options: { id: PracticeOptionId; text: string }[];
  correct: PracticeOptionId;
  explanation: string;
  resources?: { label: string; url: string }[];
};

export type YesNoStatement = { text: string; correct: "Ja" | "Nein" };

export type YesNoQuestion = {
  type: "yesno";
  id: string;
  topicId: string;
  prompt: string;
  statements: YesNoStatement[];
  explanation: string;
  resources?: { label: string; url: string }[];
};

export type MatchingItem = { id: string; label: string };
export type MatchingDescription = { id: string; text: string; correctItemId: string };

export type MatchingQuestion = {
  type: "matching";
  id: string;
  topicId: string;
  prompt: string;
  instructions?: string;
  items: MatchingItem[];
  descriptions: MatchingDescription[];
  explanation: string;
  resources?: { label: string; url: string }[];
};

export type PracticeQuestion = SingleChoiceQuestion | YesNoQuestion | MatchingQuestion;

export type PracticeTopic = {
  id: string;
  title: string;
  /** Real target size once the full question bank is loaded. */
  totalQuestions: number;
  /** True while no authored questions exist yet for this topic. */
  locked?: boolean;
};

